//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_PopUp = function (disGubun, chgGubun) {
  var rtnList = new Array();
  switch (disGubun) {
    case "Customer":
      // Customer
      pCode = cnd_ed_custCd.getValue().trim();
      if (pCode == "") {
        pName = cnd_ed_custNm.getValue().trim();
      } else {
        pName = "";
      }
      udc_custCd.ilCommonPopUp(scwin.callbackEngClntInfo,
      // XML상의 SELECT ID	                                                   							
      pCode,
      // 화면에서의 ??? Code Element의	Value                                  
      pName,
      // 화면에서의 ??? Name Element의	Value                                  
      chgGubun,
      // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
      '10',
      // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
      'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN',
      // Title순서	                                                           
      '140,300,100,100,100,100,100,,,100',
      // 보여주는 각 컬럼들의 폭	                                               
      '8,9',
      // 컬럼중에서 숨기는	컬럼 지정	                                       
      null,
      // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
      '500',
      // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
      '500',
      // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
      null,
      // 윈도우 위치 Y좌표	                                                   
      null,
      // 윈도우 위치 X좌표                                                       
      null,
      // 중복체크여부	("F")                                                      
      "F",
      // 전체검색허용여부	("F")                                                  
      'Customer search,Customer Code,Customer Name');
      //if(typeof(rtnList) != "undefined"){
      //cfSetReturnValue(rtnList, cnd_ed_custCd,cnd_ed_custNm);				
      //}					
      break;
    case "Vessel":
      pCode = ed_csvslcd.getValue().trim();
      if (pCode == "") {
        pName = ed_txt_csvslnm.getValue().trim();
      } else {
        pName = "";
      }
      udc_csvslcd.setSelectId("retrieveOrdVsslInfo");
      udc_csvslcd.ilCommonPopUp(scwin.udc_csvslcd_callBackFunc // XML상의 SELECT ID
      , pCode // 화면에서의 ??? Code Element의	Value
      , pName // 화면에서의 ??? Name Element의	Value
      , chgGubun // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
      , '2' // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
      , 'Vessel Code,Vessel Name' // Title순서
      , '130,300' // 보여주는 각 컬럼들의 폭
      , "3,4,5,6,7,8,9,10" // 컬럼중에서 숨기는	컬럼 지정
      , null // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
      , '500' // POP-UP뛰을때 원도우의	사용자 정의	폭
      , '500' // POP-UP뛰을때 우도우의	사용자 정의	높이
      , null // 윈도우 위치 Y좌표
      , null // 윈도우 위치 X좌표
      , null // 중복체크여부	("F")
      , 'F' // 전체검색허용여부	("F")
      , "Vessel Search, Vessel Code, Vessel Name"); // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
      break;
  }
};
scwin.udc_disCd_onviewchangeCodeEvent = function (info) {
  var strClntNo = "";
  strClntNo = cnd_ed_custCd.getValue().trim();

  //if (cnd_ed_custCd.Modified ) {
  if (strClntNo.length > 0) {
    cnd_ed_custNm.setValue("");
    scwin.f_PopUp('Customer', 'T');
  } else {
    cnd_ed_custNm.setValue("");
  }
  //}
};
scwin.udc_csvslcd_callBackFunc = function (rtnList) {
  if (rtnList != null) {
    if (rtnList[0] != "N/A") {
      $c.gus.cfSetReturnValue($p, rtnList, ed_csvslcd, ed_txt_csvslnm);
    }
  }
};
scwin.udc_custCd_onclickEvent = function (e) {
  scwin.f_PopUp('Customer', 'F');
};
scwin.udc_custCd_onviewchangeCodeEvent = function (info) {
  scwin.f_PopUp('Customer', 'F');
};
scwin.udc_custCd_onviewchangeNameEvent = function (info) {
  scwin.f_PopUp('Customer', 'F');
};
scwin.udc_csvslcd_onclickEvent = function (e) {
  scwin.f_PopUp('Vessel', 'F');
};
scwin.udc_csvslcd_onviewchangeNameEvent = function (info) {
  scwin.f_PopUp('Vessel', 'T');
};
scwin.udc_csvslcd_onblurCodeEvent = function (e) {
  scwin.f_BeforePopUpEd(ed_txt_csvslnm, ed_csvslcd, "Vessel", "T", "T");
};
scwin.callbackEngClntInfo = function (rtnList) {
  $c.gus.cfSetReturnValue($p, rtnList, cnd_ed_custCd, cnd_ed_custNm);
};

//-------------------------------------------------------------------------
// function	name : f_BeforePopUpEd
// function	desc : 공통팝업 열기 전에 체크- EMEDIT onKillFocus 이벤트	발생시
//					nmObj-코드명(text),	cdObj-코드(emedit),	gubun1
//-------------------------------------------------------------------------
scwin.f_BeforePopUpEd = function (nmObj, cdObj, gubun1, pWinCloseTF) {
  var cdObjVal = cdObj.getValue().trim();
  if (cdObjVal == "") {
    nmObj.value = "";
  } else {
    nmObj.value = "";
    scwin.f_PopUp(gubun1, pWinCloseTF);
  }
};
scwin.f_DisablePopUpObj = function () {
  $c.gus.cfDisableObjects($p, [udc_custCd, ed_input19, ed_input4, ed_input20, ed_input7, udc_csvslcd, ed_input21, ed_input8, rd_radio1, ed_input22, ed_bkEtd, ed_bkEta, ed_docClosingDt, ed_docClosingTime, ed_cargoClosingDt, ed_cargoClosingTime, ed_pkPlNm, ed_input25, ed_input11, btn_trigger7, ed_input12, btn_trigger8, ed_input13, btn_trigger9, ed_input14, btn_trigger10, ed_input26, ed_input15, ed_input16, ed_input17, ed_input18, ica_inputCalendar3, ed_input24, ed_input28, ed_input27, txt_textarea1, btn_Cancel]);
  $c.gus.cfEnable($p, btn_Create);
};
scwin.f_enableObj = function () {
  $c.gus.cfEnable($p, [udc_custCd, ed_input19, ed_input4, ed_input20, ed_input7, udc_csvslcd, ed_input21, ed_input8, rd_radio1, ed_input22, ed_bkEtd, ed_bkEta, ed_docClosingDt, ed_docClosingTime, ed_cargoClosingDt, ed_cargoClosingTime, ed_pkPlNm, ed_input25, ed_input11, btn_trigger7, ed_input12, btn_trigger8, ed_input13, btn_trigger9, ed_input14, btn_trigger10, ed_input26, ed_input15, ed_input16, ed_input17, ed_input18, ica_inputCalendar3, ed_input24, ed_input28, ed_input27, txt_textarea1, btn_Cancel]);
  $c.gus.cfDisableObjects($p, btn_Create);
};
scwin.f_DisableObjAfterRetrieve = function () {
  $c.gus.cfDisableObjects($p, [btn_Cancel, btn_Save]);
  $c.gus.cfEnable($p, [btn_Copy, btn_Create, btn_Update, btn_Print, btn_Delete]);
};
scwin.btn_fieldClear_onclick = function (e) {
  ds_search.setEmptyValue();
};
scwin.btn_retrieve_onclick = async function (e) {
  if (ed_input1.getValue().trim() == "" && ed_input2.getValue().trim() == "" && ed_input3.getValue().trim() == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_065, ["조회조건을 입력"]); // @은(는) 필수 입력 항목입니다.
    return;
  } else {
    ds_search.set("kcomcd", scwin.hd_kcomcd);
    ds_search.set("bkbltype", scwin.hd_bkbltype);
    ds_bookingDoorOrder.removeAll();
    ds_containerBookingList.removeAll();
  }
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_retrieve_submitdone = async function (e) {
  // 조회 결과 없음
  if (ds_containerBookingList.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003); // 해당되는 자료가 존재하지 않습니다
    scwin.f_Set("INIT");
    return;
  } else {
    ds_containerBookingList.setRowPosition(0);
    scwin.f_DisableObjAfterRetrieve();
    tbx_totalRows.setValue(ds_bookingDoorOrder.getRowCount());
  }
};
scwin.f_Set = function (gubun) {
  switch (gubun) {
    case "INIT":
      //초기화
      $c.gus.cfDisableKeyData($p); // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_Cancel, btn_Save, btn_Save, btn_Delete, btn_Update, btn_Print]);
      $c.gus.cfEnableBtnOnly($p, [btn_Create]);
      $c.gus.cfEnableObjects($p, [ed_input1, ed_input2, ed_input3]); // 조회조건.
      scwin.f_DisablePopUpObj();
      scwin.statusFlag = "I";
      break;
    case "RETRIEVE":
      //조회모드	
      $c.gus.cfDisableKeyData($p);
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Cancel]);
      $c.gus.cfEnableBtnOnly($p, [btn_Copy, btn_Create, btn_Delete, btn_Print]);
      if (scwin.statusFlag == "C") {
        $c.gus.cfDisableBtnOnly($p, [btn_Update]);
      } else {
        $c.gus.cfEnableBtnOnly($p, [btn_Update]);
      }
      $c.gus.cfEnableObjects($p, [ed_input1, ed_input2, ed_input3]); // 조회조건.
      scwin.statusFlag = ""; // flag null  					          	                    
      break;
    case "CREATE":
      //신규
      $c.gus.cfEnableKeyData($p);
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_Create, btn_Update, btn_Delete, btn_Print]);
      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel]);
      $c.gus.cfDisableObjects($p, [ed_input1, ed_input2, ed_input3]); // 조회조건.    
      scwin.f_enableObj();
      scwin.statusFlag = "C";
      break;
    case "UPDATE":
      //B/L발행 후에는 일부항목만 수정
      ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
      ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkNo", ed_input6.getValue());
      $c.gus.cfDisableBtnOnly($p, [btn_Copy, btn_Create, btn_Update, btn_Delete]);
      $c.gus.cfEnableBtnOnly($p, [btn_Cancel, btn_Save, btn_Print]);
      $c.gus.cfDisableKey($p);
      $c.gus.cfDisableObjects($p, [ed_input1, ed_input2, ed_input3]); // 조회조건.       
      scwin.f_enableObj();
      scwin.statusFlag = "U";
      break;
    case "SAVE":
      $c.gus.cfDisableBtnOnly($p, [btn_Save, btn_Delete, btn_Cancel, btn_Print]);
      $c.gus.cfEnableBtnOnly($p, [btn_Update, btn_Create]);
      scwin.f_Set("RETRIEVE");
      break;
  }
};
scwin.btn_Copy_onclick = function (e) {
  scwin.f_Set("CREATE");
  ds_search.set("bkNo", "");
  if (ds_containerBookingList.getRowCount() > 0) {
    ds_containerBookingList.modifyRowStatus(0, "C"); // insert 로 변경.
    ds_containerBookingList.setCellData(0, "bkNo", "");
  }
};
scwin.btn_Cancel_onclick = function (e) {
  if (scwin.statusFlag == "C") {
    scwin.f_Set("INIT");
  } else {
    scwin.f_Set("RETRIEVE");
    ds_containerBookingList.undoAll();
    ds_bookingDoorOrder.undoAll();
    ed_input1.focus();
  }
};
scwin.btn_Create_onclick = function (e) {
  scwin.f_Set("CREATE");
  ds_search.set("bkNo", "");
  ds_containerBookingList.removeAll();
  ds_containerBookingList.insertRow();
  scwin.f_Check(0);
};
scwin.btn_Update_onclick = function (e) {
  if (ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "bkNo") == "") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["HEADER"]); // @은(는) 필수 입력 항목입니다.
    return;
  } else {
    scwin.f_Set("UPDATE");
  }
};
scwin.btn_Save_onclick = async function (e) {
  var isChanged = ds_containerBookingList.getModifiedIndex().length > 0 || ds_bookingDoorOrder.getModifiedIndex().length > 0;
  if (!isChanged) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["Booking Sheet"]); // @은(는) 변경된 사항이 없습니다.
    return;
  }
  if (scwin.f_validate()) {
    if (await $c.win.confirm($p, E_MSG_CM_CRM_001)) {
      //저장하시겠습니까?
      if (ds_containerBookingList.getCellData(0, "bkNo") == "") {
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
        ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "bkbltype", scwin.hd_bkbltype);
      }
      ds_containerBookingList.setCellData(ds_containerBookingList.getRowPosition(), "upddt", "");
      ds_retrieveNo.removeAll();
      $c.sbm.execute($p, sbm_save);
    }
  }
};
