scwin._checkContainerTypeAndPopup = async function (inputComp, popupKey) {
  if (!inputComp) return true;
  var code = String(inputComp.getValue() || "").trim();
  if (code === "") return true;

  // 존재 여부 체크: getMatchedIndex
  var idx = typeof ds_containerType.getMatchedIndex === "function" ? ds_containerType.getMatchedIndex("code", code) : -1;
  if (idx < 0) {
    // 메시지 표준에 맞게 교체 권장
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_049, ["Container Type"]);
    // 잘못 입력했으면 값 비우는게 UX상 더 안전
    inputComp.setValue("");
    return false;
  }
  scwin.f_OpenCommonPopUp(popupKey, "T", "F", "F");
  return true;
};
